use crate::models::task::Task;
use crate::storage;

pub fn run(format: crate::ExportFormat, output: Option<String>, tag: Option<String>, priority: Option<u8>) {
    let tasks = storage::load_tasks().expect("Failed to load tasks");
    // Apply filters then format output
    let content = match format {
        crate::ExportFormat::Csv => format_csv(&tasks),
        crate::ExportFormat::Json => format_json(&tasks),
        crate::ExportFormat::Markdown => format_markdown(&tasks),
    };
    match output {
        Some(path) => std::fs::write(&path, &content).expect("Failed to write file"),
        None => print!("{}", content),
    }
}

